mapper.select:
/* rcp.rcpMgmt.openDataUpd.setCrdtLoanRvlProc */ SELECT 'Y' AS CRDT_LOAN_APPL_YN , 'R' AS CRDT_LOAN_TSK /* 여신부활 */ , '20' AS TSK_TP /* 개통 */ , '2' AS CRDT_LOAN_CL , A.OPEN_AGNT_CD AS ORGN_ID /* 개통대리점 */ , DECODE(NVL(C.MODEL_MONTHLY, '0'), '0', NVL(C.MODEL_DISCOUNT2, 0), NVL(C.MODEL_PRICE, 0) + NVL(C.MODEL_PRICE_VAT, 0)) AS CRDT_LOAN_AMT /* 여신금액 */ , TO_CHAR(SYSDATE, 'YYYYMMDD') AS CRDT_LOAN_DT /* 여신일자 */ , A.CUSTOMER_ID AS CUST_ID /* 고객번호 */ , A.CONTRACT_NUM AS SRVC_CNTR_NUM /* 계약번호 */ , 1 AS QNTY , NVL(C.MODEL_PRICE, 0) AS OUT_AMT /* 출고단가 */ , NVL(C.MODEL_INSTALLMENT, 0) AS INST_AMT /* 할부원금 */ , #{regstId} AS USER_ID FROM MSP_JUO_SUB_INFO A /* 계약현행화 */ , MSP_REQUEST B /* 가입신청 */ , MSP_REQUEST_SALEINFO C /* 판매정보 */ WHERE A.SUB_STATUS NOT IN ('C') /* C: 해지 */ AND A.PPPO = 'PO' /* 후불 */ AND A.SVC_CNTR_NO IS NOT NULL AND A.CONTRACT_NUM = B.CONTRACT_NUM AND B.OPER_TYPE NOT IN ('ICN3') /* 명의변경 제외 */ AND B.REQUEST_STATE_CODE = '21' /* 개통완료 */ AND B.PSTATE = '00' /* 정상 */ AND B.REQUEST_KEY = C.REQUEST_KEY AND C.MODEL_SALE_POLICY_CODE IS NOT NULL /* 판매정책코드 여부 */
AND NVL(C.MODEL_PRICE, 0) <> 0
AND A.CONTRACT_NUM = #{contractNum}
